var rawKey = String(java.get('key') || '').trim();
if (/^\d+$/.test(rawKey)) {
    result = source.bookSourceUrl + '/api/fqnovel/book/' + rawKey;
} else {
    var currentPage = java.get('current_page') || '1';
    java.put('current_page', (parseInt(currentPage) + 1).toString());
    var searchId = java.get('search_id');
    if (searchId && currentPage != '1') {
        result = result + '&searchId=' + encodeURIComponent(searchId);
    }
}
